'use strict';

const { fork } = require('child_process');
const http = require('http');
const { getServerPath, getDataDir } = require('./utils/paths');

const SERVER_PORT = 20128;
const POLL_INTERVAL_MS = 500;
const POLL_TIMEOUT_MS = 30000;
const SHUTDOWN_TIMEOUT_MS = 5000;
const MAX_RESTART_RETRIES = 3;

/**
 * Server Process Manager
 *
 * Manages the lifecycle of the embedded Next.js standalone server:
 * - Spawns the server as a child process
 * - Polls for readiness
 * - Handles graceful shutdown
 * - Detects crashes and auto-restarts (up to MAX_RESTART_RETRIES)
 */

/** @type {import('child_process').ChildProcess | null} */
let serverProcess = null;

/** @type {boolean} */
let running = false;

/** @type {boolean} */
let stopping = false;

/** @type {number} */
let restartCount = 0;

/** @type {((cb: () => void) => void) | null} */
let readyCallback = null;

/** @type {((cb: (err: Error) => void) => void) | null} */
let errorCallback = null;

/**
 * Polls the server health endpoint until it responds with HTTP 200.
 * @returns {Promise<void>} Resolves when server is ready, rejects on timeout.
 */
function pollForReady() {
  return new Promise((resolve, reject) => {
    const startTime = Date.now();

    const poll = () => {
      if (Date.now() - startTime > POLL_TIMEOUT_MS) {
        reject(new Error(`Server failed to become ready within ${POLL_TIMEOUT_MS / 1000} seconds`));
        return;
      }

      const req = http.get(`http://localhost:${SERVER_PORT}/api/settings`, (res) => {
        if (res.statusCode === 200) {
          // Consume response data to free up memory
          res.resume();
          resolve();
        } else {
          res.resume();
          setTimeout(poll, POLL_INTERVAL_MS);
        }
      });

      req.on('error', () => {
        // Server not ready yet, retry
        setTimeout(poll, POLL_INTERVAL_MS);
      });

      // Set a short timeout on the request itself to avoid hanging
      req.setTimeout(2000, () => {
        req.destroy();
        setTimeout(poll, POLL_INTERVAL_MS);
      });
    };

    poll();
  });
}

/**
 * Spawns the Next.js standalone server as a child process.
 * Sets DATA_DIR, PORT, and NODE_ENV environment variables.
 * Polls for readiness and invokes the ready or error callback.
 *
 * @returns {Promise<void>} Resolves when the server is ready.
 */
async function start() {
  if (running) {
    return;
  }

  stopping = false;
  const serverPath = getServerPath();
  const dataDir = getDataDir();

  const env = {
    ...process.env,
    DATA_DIR: dataDir,
    PORT: String(SERVER_PORT),
    NODE_ENV: 'production',
  };

  serverProcess = fork(serverPath, [], {
    env,
    stdio: 'pipe',
    silent: true,
  });

  // Handle child process exit for crash detection
  serverProcess.on('exit', (code, signal) => {
    running = false;
    serverProcess = null;

    // If we're intentionally stopping, don't restart
    if (stopping) {
      return;
    }

    // Crash detected — attempt auto-restart
    if (restartCount < MAX_RESTART_RETRIES) {
      restartCount++;
      start().catch((err) => {
        if (errorCallback) {
          errorCallback(err);
        }
      });
    } else {
      const err = new Error(
        `Server crashed ${MAX_RESTART_RETRIES} times. Last exit code: ${code}, signal: ${signal}`
      );
      if (errorCallback) {
        errorCallback(err);
      }
    }
  });

  // Handle spawn errors
  serverProcess.on('error', (err) => {
    running = false;
    serverProcess = null;
    if (errorCallback) {
      errorCallback(err);
    }
  });

  // Wait for the server to become ready
  try {
    await pollForReady();
    running = true;
    restartCount = 0; // Reset on successful start
    if (readyCallback) {
      readyCallback();
    }
  } catch (err) {
    // Timeout or polling failure — kill the process and report error
    if (serverProcess) {
      serverProcess.kill('SIGTERM');
      serverProcess = null;
    }
    running = false;
    if (errorCallback) {
      errorCallback(err);
    }
    throw err;
  }
}

/**
 * Gracefully stops the server process.
 * Sends SIGTERM first, waits up to 5 seconds, then force-kills if still running.
 *
 * @returns {Promise<void>} Resolves when the server has stopped.
 */
function stop() {
  return new Promise((resolve) => {
    stopping = true;

    if (!serverProcess) {
      running = false;
      resolve();
      return;
    }

    const pid = serverProcess.pid;

    // Listen for the process to exit
    const onExit = () => {
      clearTimeout(killTimer);
      running = false;
      serverProcess = null;
      resolve();
    };

    serverProcess.once('exit', onExit);

    // Send SIGTERM for graceful shutdown
    try {
      serverProcess.kill('SIGTERM');
    } catch (e) {
      // Process may have already exited
      running = false;
      serverProcess = null;
      resolve();
      return;
    }

    // If still running after timeout, force kill
    const killTimer = setTimeout(() => {
      if (serverProcess) {
        serverProcess.removeListener('exit', onExit);
        try {
          // On Windows, process.kill with no signal sends SIGTERM.
          // Use taskkill for forceful termination on Windows.
          if (process.platform === 'win32') {
            const { execSync } = require('child_process');
            try {
              execSync(`taskkill /pid ${pid} /T /F`, { stdio: 'ignore' });
            } catch (e) {
              // Process may have already exited
            }
          } else {
            serverProcess.kill('SIGKILL');
          }
        } catch (e) {
          // Process may have already exited
        }
        running = false;
        serverProcess = null;
        resolve();
      }
    }, SHUTDOWN_TIMEOUT_MS);
  });
}

/**
 * Returns whether the server process is currently running and ready.
 * @returns {boolean}
 */
function isRunning() {
  return running;
}

/**
 * Registers a callback to be invoked when the server becomes ready.
 * @param {() => void} cb
 */
function onReady(cb) {
  readyCallback = cb;
}

/**
 * Registers a callback to be invoked when a server error occurs.
 * @param {(err: Error) => void} cb
 */
function onError(cb) {
  errorCallback = cb;
}

module.exports = {
  start,
  stop,
  isRunning,
  onReady,
  onError,
};

'use strict';

const fs = require('fs');
const path = require('path');
const { getDataDir } = require('./paths');

/**
 * Required subdirectories within the data directory.
 * These are created on first launch to ensure the server has the expected
 * filesystem structure for database, logs, and MITM configuration.
 */
const REQUIRED_SUBDIRS = ['db', 'logs', 'mitm'];

/**
 * Ensures the `.9router-data/` directory and its required subdirectories exist.
 *
 * Called before spawning the server process to guarantee the data directory
 * structure is in place. If the directory already exists, this is a no-op
 * (recursive mkdir does not throw for existing directories).
 *
 * @returns {string} The resolved absolute path to the data directory.
 */
function ensureDataDir() {
  const dataDir = getDataDir();

  if (!fs.existsSync(dataDir)) {
    fs.mkdirSync(dataDir, { recursive: true });
  }

  for (const subdir of REQUIRED_SUBDIRS) {
    const subdirPath = path.join(dataDir, subdir);
    if (!fs.existsSync(subdirPath)) {
      fs.mkdirSync(subdirPath, { recursive: true });
    }
  }

  return dataDir;
}

module.exports = {
  ensureDataDir,
  REQUIRED_SUBDIRS,
};

